#include<bits/stdc++.h>
using namespace std;
long long out[300010],ans[300010],id,n,m,k,w[300010],v[300010];
vector<pair<long long,long long>> mp[300010];
map<long long,long long> dis[300010],vis[300010];
long long up(long long x,long long y)
{
    return v[y-1]-v[x-1];
}
long long down(long long x,long long y)
{
    return w[x]-w[y];
}
void dijkstra()
{
    priority_queue<pair<long long,pair<long long,long long>>,vector<pair<long long,pair<long long,long long>>>,greater<pair<long long,pair<long long,long long>>>> q;
    q.push({0,{1,1}});
    vis[1][1]=1;
    dis[1][1]=0;
    ans[1]=0;
    while(!q.empty())
    {
        auto t=q.top();
        q.pop();
        long long d=t.first,u=t.second.first,p=t.second.second;
        if(dis[u][p]!=d)
        {
            continue;
        }
        if(p!=1&&out[u])
        {
            long long tmp=min(p-1,out[u]);
            if(!vis[u][tmp]||dis[u][tmp]>d+down(p,tmp))
            {
                dis[u][tmp]=d+down(p,tmp);
                vis[u][tmp]=1;
                q.push({dis[u][tmp],{u,tmp}});
            }
        }
        if(p<min(k,out[u]))
        {
            if(!vis[u][p+1]||dis[u][p+1]>d+up(p,p+1))
            {
                dis[u][p+1]=d+up(p,p+1);
                vis[u][p+1]=1;
                q.push({dis[u][p+1],{u,p+1}});
            }
        }
        if(p>out[u])
        {
            continue;
        }
        long long v=mp[u][p-1].first,val=mp[u][p-1].second;
        if(!vis[v][p]||dis[v][p]>d+val)
        {
            dis[v][p]=d+val;
            vis[v][p]=1;
            ans[v]=min(ans[v],dis[v][p]);
            q.push({dis[v][p],{v,p}});
        }
    }
}
int main()
{
    scanf("%lld%lld%lld%lld",&id,&n,&m,&k);
    for(long long i=1;i<k;i++)
    {
        scanf("%lld",&v[i]);
        v[i]+=v[i-1];
    }
    for(long long i=2;i<=k;i++)
    {
        scanf("%lld",&w[i]);
        w[i]+=w[i-1];
    }
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&out[i]);
        for(long long j=1;j<=out[i];j++)
        {
            long long y,z;
            scanf("%lld%lld",&y,&z);
            mp[i].push_back(make_pair(y,z));
        }
    }
    memset(ans,0x3f,sizeof(ans));
    dijkstra();
    for(long long i=1;i<=n;i++)
    {
        if(ans[i]>1e18)
        {
            printf("-1 ");
            continue;
        }
        printf("%lld ",ans[i]);
    }
    return 0;
}
